import * as t from "io-ts";
import { intentTypes } from "./intentType";
import { Amount } from "./amount";
import { BaseStakeIntent } from "./baseStakeIntent";
import { Optional } from "../../../utils";

/**
 * @title Walrus Undelegate Intent
 *
 * @param {string} stakedSuiObjectId - The original StakedWal object id
 * @param {Amount} amount - The amount to undelegate
 * @param {string} sharedStakingObjectId - The staking object id
 */
export const WalrusUndelegateIntent = t.intersection([
  BaseStakeIntent,
  t.type({
    intentType: intentTypes.undelegate,
    stakedSuiObjectId: t.string,
    sharedStakingObjectId: t.string,
  }),
  t.partial({
    amount: Optional(Amount),
  }),
]);

export type WalrusUndelegateIntent = t.TypeOf<typeof WalrusUndelegateIntent>;
